+    : TValue extends Set<infer TItem>
+      ? ContainsRecur<TItem>
+      : TValue extends (infer TItem)[]
+        ? ContainsRecur<TItem>
+        : TValue extends object
+          ? true extends {
+              [TKey in keyof TValue]: ContainsRecur<TValue[TKey]>;
+            }[keyof TValue]
+            ? true
+            : false
+          : false;
+
+/**
+ * A schema without unresolved recursive placeholders.
+ */
+export type SchemaWithoutRecur<
+  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> = true extends
+  | ContainsRecur<InferInput<TSchema>>
+  | ContainsRecur<InferOutput<TSchema>>
+  ? never
+  : unknown;
+
+/**
+ * Recursive schema placeholder.
+ */
+export const Recur: Recur = {
+  kind: 'schema',
+  type: 'recur',
+  reference: recursive,
+  expects: 'unknown',
+  async: false,
+  get '~standard'() {
+    return _getStandardProps(this);
+  },
+  '~run'() {
+    throw new Error('Recursive schema placeholder must be wrapped with recursive().');
+  },
+};
+
+/**
+ * Creates a recursive schema.
+ *
+ * @param wrapped The schema with recursive placeholders.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  const schema = {
+    kind: 'schema' as const,
+    type: 'recursive' as const,
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false as const,
+    wrapped: undefined as unknown as TWrapped,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      return this.wrapped['~run'](dataset, config);
+    },
+  } satisfies Omit<RecursiveSchema<TWrapped>, 'wrapped'> & {
+    wrapped: TWrapped;
+  };
+  schema.wrapped = _replaceRecur(wrapped, schema) as TWrapped;
+  return schema as RecursiveSchema<TWrapped>;
+}
+
+function _replaceRecur<TValue>(value: TValue, recur: unknown): TValue {
+  if (value === Recur) {
+    return recur as TValue;
+  }
+  if (!value || typeof value !== 'object') {
+    return value;
+  }
+
+  const values = new WeakMap<object, object>();
+  const replace = (current: object): object => {
+    if (current === Recur) {
+      return recur as object;
+    }
+    const cached = values.get(current);
+    if (cached) {
+      return cached;
+    }
+
+    const replacement = Array.isArray(current)
+      ? []
+      : Object.create(Object.getPrototypeOf(current));
+    values.set(current, replacement);
+    for (const key of Reflect.ownKeys(current)) {
+      const descriptor = Object.getOwnPropertyDescriptor(current, key)!;
+      if ('value' in descriptor && descriptor.value && typeof descriptor.value === 'object') {
+        descriptor.value = replace(descriptor.value);
+      }
+      Object.defineProperty(replacement, key, descriptor);
+    }
+    return replacement;
+  };
+
+  return replace(value) as TValue;
