+describe('recursive', () => {
+  test('should resolve recursive placeholders in arrays', () => {
+    const schema = recursive(
+      object({ value: string(), children: array(Recur) })
+    );
+    const input = { value: 'root', children: [{ value: 'child', children: [] }] };
+
+    expect(parse(schema, input)).toEqual(input);
+    expect(schema.wrapped.entries.children.item).toBe(schema);
+  });
+
+  test('should resolve recursive placeholders in record, map and set values', () => {
+    const recordSchema = recursive(record(string(), Recur));
+    const mapSchema = recursive(map(string(), Recur));
+    const setSchema = recursive(set(Recur));
+
+    expect(parse(recordSchema, { child: {} })).toEqual({ child: {} });
+    expect(parse(mapSchema, new Map([['child', new Map()]]))).toEqual(
+      new Map([['child', new Map()]])
+    );
+    expect(parse(setSchema, new Set([new Set()]))).toEqual(new Set([new Set()]));
+  });
+
+  test('should resolve recursive placeholders in pipes', () => {
+    const schema = recursive(
+      pipe(
+        object({ value: string(), children: array(Recur) }),
+        transform((input) => ({ ...input, value: input.value.length }))
+      )
+    );
+
+    expect(
+      parse(schema, { value: 'root', children: [{ value: 'child', children: [] }] })
+    ).toEqual({ value: 4, children: [{ value: 5, children: [] }] });
+  });
+
+  test('should resolve recursive placeholders in intersections', () => {
+    const schema = recursive(
+      intersect([
+        object({ value: string() }),
+        object({ children: array(Recur) }),
+      ])
+    );
+    const input = { value: 'root', children: [{ value: 'child', children: [] }] };
+
+    expect(parse(schema, input)).toEqual(input);
+  });
+});
